#include "vimax/modules/booking_module.hpp"
namespace vimax {std::string BookingModule::id() const{return "vimax.booking";}std::string BookingModule::name() const{return "Vimax Booking";}std::vector<std::string> BookingModule::supported_intents() const{return {"booking.create"};}WorkflowPlan BookingModule::build_plan(const Intent&i) const{WorkflowPlan p;p.id="booking.create.v1";p.title="Создать запись к мастеру";for(auto*r:{"master","date","time"})if(!i.slots.contains(r))p.missing_fields.emplace_back(r);p.actions.push_back({id(),"reserve_slot",i.slots,RiskLevel::medium,ConfirmationMode::none});p.executable=p.missing_fields.empty();return p;}ActionResult BookingModule::execute(const Action&a){if(a.operation!="reserve_slot")return {false,"Неизвестная операция записи",{}};return {true,"Слот зарезервирован. В production здесь будет транзакция с календарём и уведомлениями.",{{"booking_status","reserved"}}};}}
